<div class="admin-container"><h1><i class="fas fa-credit-card"></i> Gerenciar Pagamentos</h1><?php if (!empty($_SESSION['success'])): ?><div class="alert alert-success"><?php echo htmlspecialchars($_SESSION['success']); unset($_SESSION['success']); ?></div><?php endif; ?><form class="filter" method="GET"><input type="hidden" name="page" value="admin/pagamentos"><select name="status"><option value="">Todos</option><?php foreach(['pendente','aprovado','falhou','reembolsado'] as $st): ?><option value="<?php echo $st; ?>" <?php echo $status===$st?'selected':''; ?>><?php echo ucfirst($st); ?></option><?php endforeach; ?></select><button class="btn-primary">Filtrar</button></form><section class="admin-panel"><div class="table-responsive"><table><thead><tr><th>Usuário</th><th>Valor</th><th>Plano</th><th>Status</th><th>Referência</th><th>Data</th><th>Ações</th></tr></thead><tbody><?php foreach($payments as $p): ?><tr><td><?php echo htmlspecialchars($p['nome_completo']); ?><br><small><?php echo htmlspecialchars($p['email']); ?></small></td><td><?php echo number_format((float)$p['valor_kwanza'],2,',','.'); ?> Kz</td><td><?php echo htmlspecialchars($p['plano_comprado']); ?></td><td><?php echo htmlspecialchars($p['status']); ?></td><td><?php echo htmlspecialchars($p['referencia_multicaixa']); ?></td><td><?php echo date('d/m/Y H:i', strtotime($p['data_solicitacao'])); ?></td><td><a href="index.php?page=admin/pagamento-confirmar&id=<?php echo (int)$p['id']; ?>">Confirmar</a> | <a href="index.php?page=admin/pagamento-reembolsar&id=<?php echo (int)$p['id']; ?>">Reembolsar</a> | <a href="index.php?page=admin/pagamento-falhar&id=<?php echo (int)$p['id']; ?>">Falhou</a></td></tr><?php endforeach; ?></tbody></table></div></section></div><style>.admin-container{max-width:1280px;margin:0 auto;padding:34px 20px}.admin-tabs{max-width:1280px;margin:24px auto 0;padding:0 20px;display:flex;gap:10px;flex-wrap:wrap}.admin-tabs a{background:#fff;border:1px solid #e5e7eb;color:#2c3e66;text-decoration:none;padding:10px 14px;border-radius:10px}.admin-panel{background:#fff;border-radius:16px;padding:22px;margin:18px 0;box-shadow:0 8px 28px rgba(0,0,0,.06)}.filter{display:flex;gap:10px;margin:14px 0}.filter select{padding:10px;border-radius:8px;border:1px solid #ddd}table{width:100%;border-collapse:collapse}th,td{padding:12px;border-bottom:1px solid #eee;text-align:left}.table-responsive{overflow-x:auto}.alert{padding:12px;border-radius:8px;margin:12px 0}.alert-success{background:#d4edda}</style>
